+fn make_claim(id: &str, category: ClaimCategory, comp: &str) -> StabilityClaim {
+    StabilityClaim {
+        claim_id: id.to_string(),
+        category,
+        composition_id: comp.to_string(),
+        description: format!("test claim {id}"),
+    }
+}
